<?php
namespace App\Domain\Combat\Data;use App\Domain\Combat\CombatSide;use InvalidArgumentException;final class CombatParticipantState {private $stats;private $health;private $side;private $position;public function __construct(CombatantStats $stats,$health,$side,$position){if(!in_array($side,CombatSide::values(),true)||!is_int($position)||$position<1||!is_int($health)||$health<0||$health>$stats->maxHealth())throw new InvalidArgumentException('Invalid participant.');$this->stats=$stats;$this->health=$health;$this->side=$side;$this->position=$position;}public function stats(){return$this->stats;}public function identifier(){return$this->stats->identifier();}public function name(){return$this->stats->name();}public function currentHealth(){return$this->health;}public function sideIdentifier(){return$this->side;}public function position(){return$this->position;}public function alive(){return$this->health>0;}}
